  function checkEvolution(key, level) {
    const evo = EVOLUTION_TABLE[key];
    if (!evo) return null;
    return level >= evo.level ? evo : null;
  }

  function evolve(fromKey, toKey, slotIndex) {
    if (!POKEMON_DATA[toKey]) return false;
    const team = SaveSystem.getTeam();
    if (team[slotIndex] !== fromKey) return false;
    team[slotIndex] = toKey;
    SaveSystem.setTeam(team);
    SaveSystem.unlockPokemon(toKey);
    return true;
  }

  function checkTeamEvolutions(battleTeam) {
    const events = [];
    battleTeam.forEach((pkmn, i) => {
      const evo = checkEvolution(pkmn.key, pkmn.level);
      if (evo) {
        const success = evolve(pkmn.key, evo.into, i);
        if (success) events.push({
          fromName: POKEMON_DATA[pkmn.key]?.name,
          toName:   POKEMON_DATA[evo.into]?.name,
          fromKey:  pkmn.key, toKey: evo.into, slotIndex: i
        });
      }
    });
    return events;
  }

  function getChainString(startKey) {
    const parts = [POKEMON_DATA[startKey]?.name || startKey];
    let current = startKey;
    for (let i = 0; i < 5; i++) {
      const evo = EVOLUTION_TABLE[current];
      if (!evo) break;
      parts.push(`→ ${POKEMON_DATA[evo.into]?.name || evo.into} (Lv.${evo.level})`);
      current = evo.into;
    }
    return parts.join(' ');
  }

  return { checkEvolution, evolve, checkTeamEvolutions, getChainString };
